module RefModule(clk, rst, count);

    input  clk;
    input  rst;
    output reg [7:0] count;
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= 8'b11111111;
        else
            count <= count - 1;
    end

endmodule
